import{_ as a,c as r,o as i,ah as o}from"./chunks/framework.C-x9UAyH.js";const s="/az_despliegue_contenedores.png",g=JSON.parse('{"title":"Azure Container Registry","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"azure/acr.md","filePath":"azure/acr.md","lastUpdated":1760649277000}'),n={name:"azure/acr.md"};function t(c,e,l,d,u,p){return i(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="azure-container-registry" tabindex="-1">Azure Container Registry <a class="header-anchor" href="#azure-container-registry" aria-label="Permalink to &quot;Azure Container Registry&quot;">​</a></h1><p><strong>Azure Container Registry (ACR)</strong> es un depósito en la nube para <strong>almacenar y gestionar imágenes de contenedores</strong>, esos paquetes de software que llevan tus aplicaciones a cualquier rincón del universo digital. 🌐</p><p>Es la clave para <strong>desplegar programas en la nube</strong> 🚀 de forma ágil, ideal para proyectos grandes o cuando manejas múltiples aplicaciones al mismo tiempo. 💻</p><h2 id="azure-container-apps" tabindex="-1">Azure Container Apps <a class="header-anchor" href="#azure-container-apps" aria-label="Permalink to &quot;Azure Container Apps&quot;">​</a></h2><p>Proporciona un servicio de contenedor sin servidor específicamente diseñado para aplicaciones basadas en microservicios. Este servicio destaca por sus sólidas capacidades de escalado automático, eliminando la complejidad asociada con la gestión directa de una infraestructura.</p><ol><li><strong>Flexibilidad</strong> sin la carga operativa (enfoque en el desarrollo de apps, no en la infraestructura)</li><li>Enfoque en <strong>microservicios</strong> (facilidad de desarrollo, implementación y escalado proporcionada por el servicio)</li><li><strong>Escalado automático</strong> eficiente (las app pueden ajustar automaticamente su capacidad de respuesta a cambios n la carga de trabajo. Asegura un rendimiento óptimo sin requerir intervencion manual)</li></ol><h2 id="acr-tasks" tabindex="-1">ACR Tasks <a class="header-anchor" href="#acr-tasks" aria-label="Permalink to &quot;ACR Tasks&quot;">​</a></h2><p>ACR Tasks <strong>automatiza la creación y actualización de imágenes</strong> en Azure Container Registry, reaccionando a eventos como:</p><ul><li>📝 Tarea rapida (compilación e inserción de imagen en contenedor Azure sin necesidad de instalar el motor de Docker. Es similar a comandos docker build y docker push)</li><li>🔄 Tareas desencadenadas automaticamente (CI/CD)</li><li>⏰ Tareas de varios pasos (definir flujos de trabajos complejos en un YAML)</li></ul><p>Con <strong>ACR Tasks</strong>, se envía el contexto del código (como un repositorio GIT o archivos locales) usando el comando <code>az acr build</code> de la CLI de Azure. ¡El resultado? Imágenes construidas y almacenadas automáticamente en el registro. ✨</p><p><strong>Casos de uso</strong>:</p><ul><li>🛠️ Compilación automática al actualizar código.</li><li>⏳ Programación de builds para máxima eficiencia.</li></ul><h2 id="ciclo-de-despliegue" tabindex="-1">Ciclo de despliegue <a class="header-anchor" href="#ciclo-de-despliegue" aria-label="Permalink to &quot;Ciclo de despliegue&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Implementar en Azure Container App desde Azure Container Registry mediante CI/CD Azure Devops Pipeline y Azure CLI</p></div><p align="center"><img src="'+s+'" width="800" alt="azure acr"></p>',15)])])}const C=a(n,[["render",t]]);export{g as __pageData,C as default};
